boot.artifact:
// inferred-not-tested + 重度警告:Monaco 向 document.head 注入 100+ 样式且用 95 处动态 import 按需加载语言包;仅整页 artifact 的只读查看较可行,widget/严格 CSP 不适用。
// no-op worker stub:只读 monarch 着色可在主线程工作;但 diff 计算依赖真实 worker,stub 后 diff 可能不显示 —— 需要 diff 时应让 MonacoEnvironment.getWorker 返回自 host 的真实 worker。
self.MonacoEnvironment = { getWorker: () => ({ postMessage(){}, addEventListener(){}, removeEventListener(){}, terminate(){} }) };
import { editor } from 'https://cdn.jsdelivr.net/npm/monaco-editor@0.56.0/+esm';
const el = document.getElementById('monaco'); el.style.height = '480px';
if (data.diff) {
  const de = editor.createDiffEditor(el, { readOnly: data.readOnly ?? true, automaticLayout: true, theme: data.theme ?? 'vs', renderSideBySide: true });
  de.setModel({ original: editor.createModel(data.diff.original, data.language), modified: editor.createModel(data.value, data.language) });
} else {
  editor.create(el, { value: data.value, language: data.language ?? 'plaintext', readOnly: data.readOnly ?? true, minimap: { enabled: data.minimap ?? true }, automaticLayout: true, theme: data.theme ?? 'vs', scrollBeyondLastLine: false });
}

